var geoCache = /* @__PURE__ */ new Map();
var CACHE_TTL_MS2 = 24 * 60 * 60 * 1e3;
var PRIVATE_IP_RE = /^(127\.|10\.|172\.(1[6-9]|2\d|3[01])\.|192\.168\.|::1$|::ffff:127\.|fd|fc)/i;
function isPrivateIp(ip) {
  return !ip || PRIVATE_IP_RE.test(ip) || ip === "localhost";
}
async function lookupIp(ip) {
  if (isPrivateIp(ip)) return null;
  const cached2 = geoCache.get(ip);
  if (cached2 && Date.now() - cached2.ts < CACHE_TTL_MS2) return cached2.data;
  try {
    const res = await fetch(
      `http://ip-api.com/json/${encodeURIComponent(ip)}?fields=status,country,countryCode,regionName,city,lat,lon,isp`,
      { signal: AbortSignal.timeout(3e3) }
    );
    if (!res.ok) throw new Error(`ip-api HTTP ${res.status}`);
    const json2 = await res.json();
    if (json2.status !== "success") {
      geoCache.set(ip, { data: null, ts: Date.now() });
      return null;
    }
    const geo = {
      country: json2.country ?? "",
      countryCode: json2.countryCode ?? "",
      region: json2.regionName ?? "",
      city: json2.city ?? "",
      lat: json2.lat ?? 0,
      lon: json2.lon ?? 0,
      isp: json2.isp ?? ""
    };
    geoCache.set(ip, { data: geo, ts: Date.now() });
    return geo;
  } catch (err4) {
    logger.warn(`[geoService] Failed to lookup IP ${ip}: ${err4.message}`);
    geoCache.set(ip, { data: null, ts: Date.now() });
    return null;
  }
}
function getClientIp(req) {
  const xfwd = req.headers?.["x-forwarded-for"];
  if (xfwd) {
    const first = (typeof xfwd === "string" ? xfwd : xfwd[0]).split(",")[0].trim();
    if (first) return first;
  }
  return req.ip || req.socket?.remoteAddress || "";
}

// server/utils/aiErrorHandler.ts
function parseAiError(error48) {
  const msg = error48 instanceof Error ? error48.message : String(error48);
  const isQuota = msg.includes("RESOURCE_EXHAUSTED") || msg.includes("quota") || msg.includes("rate") || msg.includes("429");
  const isAuth = msg.includes("API key not valid") || msg.includes("INVALID_ARGUMENT") || msg.includes("API_KEY_INVALID") || msg.includes("401");
  if (isQuota) {
    return {
      isQuotaError: true,
      isAuthError: false,
      userMessage: "H\u1EC7 th\u1ED1ng AI \u0111ang b\u1EADn do l\u01B0\u1EE3ng truy c\u1EADp cao. Vui l\xF2ng th\u1EED l\u1EA1i sau \xEDt ph\xFAt.",
      httpStatus: 429
    };
  }
  if (isAuth) {
    return {
      isQuotaError: false,
      isAuthError: true,
      userMessage: "C\u1EA5u h\xECnh AI ch\u01B0a h\u1EE3p l\u1EC7. Vui l\xF2ng ki\u1EC3m tra l\u1EA1i API key trong ph\u1EA7n c\xE0i \u0111\u1EB7t h\u1EC7 th\u1ED1ng.",
      httpStatus: 503
    };
  }
  return {
    isQuotaError: false,
    isAuthError: false,
    userMessage: "D\u1ECBch v\u1EE5 AI t\u1EA1m th\u1EDDi kh\xF4ng kh\u1EA3 d\u1EE5ng. Vui l\xF2ng th\u1EED l\u1EA1i sau.",
    httpStatus: 503
  };
}
function sendAiError(res, error48, context) {
  const parsed = parseAiError(error48);
  console.error(`[AI Error][${context}]`, error48);
  res.status(parsed.httpStatus).json({
    error: parsed.userMessage,
    code: parsed.isQuotaError ? "AI_QUOTA_EXCEEDED" : parsed.isAuthError ? "AI_AUTH_ERROR" : "AI_UNAVAILABLE"
  });
}

